import isObject from "lodash/isObject";

// @or filter is an equivaluent of fakerest `q=`
export function transformOrFilter(values: any) {
  if (!isObject(values) || Array.isArray(values)) {
    throw new Error(
      "Invalid '@or' filter, expected an object as first element",
    );
  }

  const queries = Object.values(values);
  if (queries.length === 0) {
    throw new Error("Invalid '@or' filter, object is empty");
  }

  return queries[0];
}

import { LIST_REGEX_BASE, parseList } from "./listParser";

export const IN_FILTER_REGEX = new RegExp(`^\\(${LIST_REGEX_BASE}\\)$`);

export function transformInFilter(value: any) {
  if (value === "()") {
    return [];
  }

  if (typeof value !== "string" || !value.match(IN_FILTER_REGEX)) {
    throw new Error(
      `Invalid '@in' filter value, expected a string matching '${IN_FILTER_REGEX.source}', got: ${value}`,
    );
  }

  return parseList(value.slice(1, -1));
}

import { transformContainsFilter } from "./transformContainsFilter";
import { transformInFilter } from "./transformInFilter";
import { transformOrFilter } from "./transformOrFilter";

export function transformFilter(filter: Record<string, any>) {
  if (!filter) {
    return undefined;
  }
  const transformedFilters: Record<string, any> = {};
  for (const [key, value] of Object.entries(filter)) {
    if (
      key.endsWith("@eq") ||
      key.endsWith("@neq") ||
      key.endsWith("@lt") ||
      key.endsWith("@lte") ||
      key.endsWith("@gt") ||
      key.endsWith("@gte")
    ) {
      const lastIndexOfAt = key.lastIndexOf("@");
      transformedFilters[
        `${key.substring(0, lastIndexOfAt)}_${key.substring(lastIndexOfAt + 1)}`
      ] = value;
      continue;
    }

    if (key.endsWith("@is")) {
      transformedFilters[`${key.slice(0, -3)}_eq`] = value;
      continue;
    }

    if (key.endsWith("@not.is")) {
      transformedFilters[`${key.slice(0, -7)}_neq`] = value;
      continue;
    }

    if (key.endsWith("@in")) {
      transformedFilters[`${key.slice(0, -3)}_eq_any`] =
        transformInFilter(value);
      continue;
    }

    if (key.endsWith("@cs")) {
      transformedFilters[`${key.slice(0, -3)}`] =
        transformContainsFilter(value);
      continue;
    }

    // Search query
    if (key.endsWith("@or")) {
      transformedFilters["q"] = transformOrFilter(value);
      continue;
    }

    transformedFilters[key] = value;
  }
  return transformedFilters;
}

import { LIST_REGEX_BASE, parseList } from "./listParser";

export const CONTAINS_FILTER_REGEX = new RegExp(`^\\{${LIST_REGEX_BASE}\\}$`);

export function transformContainsFilter(value: any) {
  if (value === "{}") {
    return [];
  }

  if (typeof value !== "string" || !value.match(CONTAINS_FILTER_REGEX)) {
    throw new Error(
      `Invalid '@cs' filter value, expected a string matching '${CONTAINS_FILTER_REGEX.source}', got: ${value}`,
    );
  }

  return parseList(value.slice(1, -1));
}

import type { DataProvider } from "ra-core";
import { transformFilter } from "./transformFilter";

function removeSummarySuffix(resource: string) {
  return resource.endsWith("_summary")
    ? resource.replace("_summary", "")
    : resource;
}

export function withSupabaseFilterAdapter<T extends DataProvider>(
  dataProvider: T,
): T {
  return {
    ...dataProvider,
    getOne(resource, params) {
      return dataProvider.getOne(removeSummarySuffix(resource), params);
    },
    getList(resource, params) {
      return dataProvider.getList(removeSummarySuffix(resource), {
        ...params,
        filter: transformFilter(params.filter),
      });
    },
    getMany(resource, params) {
      return dataProvider.getMany(removeSummarySuffix(resource), params);
    },
    getManyReference(resource, params) {
      return dataProvider.getManyReference(removeSummarySuffix(resource), {
        ...params,
        filter: transformFilter(params.filter),
      });
    },
    create(resource, params) {
      return dataProvider.create(removeSummarySuffix(resource), params);
    },
    delete(resource, params) {
      return dataProvider.delete(removeSummarySuffix(resource), params);
    },
    deleteMany(resource, params) {
      return dataProvider.deleteMany(removeSummarySuffix(resource), params);
    },
    update(resource, params) {
      return dataProvider.update(removeSummarySuffix(resource), params);
    },
    updateMany(resource, params) {
      return dataProvider.updateMany(removeSummarySuffix(resource), params);
    },
  };
}

export const UNQUOTED_ALLOWED_CHARS = "[A-Za-zÀ-ÖØ-öø-ÿ0-9-]+";
export const QUOTED_ALLOWED_CHARS = "[A-Za-zÀ-ÖØ-öø-ÿ0-9, -]+";
export const LIST_REGEX_BASE = `(${UNQUOTED_ALLOWED_CHARS}|"${QUOTED_ALLOWED_CHARS}")(,(${UNQUOTED_ALLOWED_CHARS}|"${QUOTED_ALLOWED_CHARS}"))*`;

/**
 * List represents a list of values, quoted or not.
 *
 * e.g. 1
 * e.g 1,2
 * e.g "a","b"
 * e.g "a",b
 */
export function parseList(list: string) {
  const parsedItems = [];

  let currentItem = "";
  let currentQuoted = false;
  for (const char of list) {
    if (char === ",") {
      if (currentQuoted) {
        currentItem += char;
        continue;
      }

      parsedItems.push(currentItem);
      currentItem = "";
      continue;
    }

    if (char === '"') {
      currentQuoted = !currentQuoted;
      continue;
    }

    currentItem += char;
  }
  if (currentItem) {
    parsedItems.push(currentItem);
  }

  return parsedItems.map((v: string) => {
    const parsedFloat = Number.parseFloat(v);
    if (!Number.isNaN(parsedFloat)) {
      return parsedFloat;
    }
    return v;
  });
}

import faker from "faker/locale/en";

export const weightedArrayElement = (values: any[], weights: any) =>
  faker.random.arrayElement(
    values.reduce(
      (acc, value, index) => acc.concat(new Array(weights[index]).fill(value)),
      [],
    ),
  );

export const weightedBoolean = (likelyhood: number) =>
  faker.datatype.number(99) < likelyhood;

export const randomDate = (minDate?: Date, maxDate?: Date) => {
  const minTs =
    minDate instanceof Date
      ? minDate.getTime()
      : Date.now() - 5 * 365 * 24 * 60 * 60 * 1000; // 5 years
  const maxTs = maxDate instanceof Date ? maxDate.getTime() : Date.now();
  const range = maxTs - minTs;
  const randomRange = faker.datatype.number({ max: range });
  // move it more towards today to account for traffic increase
  const ts = Math.sqrt(randomRange / range) * range;
  return new Date(minTs + ts);
};

export const randomFloat = (min: number, max: number) =>
  parseFloat(faker.datatype.number({ min, max, precision: 0.01 }).toFixed(2));

