export const Dashboard = () => {
  const { agent } = useAgent();
  const { copilotkit } = useCopilotKit();
  const [rightTab, setRightTab] = useState("tasks");

  useCopilotSetup({
    context: {
      description: "User is viewing the CRM dashboard",
      value: null,
    },
  });

  const { registerPage } = useCopilotOverlay();

  useEffect(() => {
    return registerPage(() => setRightTab("copilot"));
  }, [registerPage]);

  const triggerAgent = useCallback(
    async (prompt: string) => {
      setRightTab("copilot");
      agent.addMessage({ id: randomUUID(), role: "user", content: prompt });
      await copilotkit.runAgent({ agent });
    },
    [agent, copilotkit],
  );

  const {
    data: dataContact,
    total: totalContact,
    isPending: isPendingContact,
  } = useGetList<Contact>("contacts", {
    pagination: { page: 1, perPage: 1 },
  });

  const { total: totalContactNotes, isPending: isPendingContactNotes } =
    useGetList<ContactNote>("contact_notes", {
      pagination: { page: 1, perPage: 1 },
    });

  const { total: totalDeal, isPending: isPendingDeal } = useGetList<Contact>(
    "deals",
    {
      pagination: { page: 1, perPage: 1 },
    },
  );

  const isPending = isPendingContact || isPendingContactNotes || isPendingDeal;

  if (isPending) {
    return null;
  }

  if (!totalContact) {
    return <DashboardStepper step={1} />;
  }

  if (!totalContactNotes) {
    return <DashboardStepper step={2} contactId={dataContact?.[0]?.id} />;
  }

  return (
    <div className="flex flex-col gap-6 mt-1">
      <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
        <div className="md:col-span-3">
          <div className="flex flex-col gap-4">
            {import.meta.env.VITE_IS_DEMO === "true" ? <Welcome /> : null}
            <HotContacts />
          </div>
        </div>
        <div className="md:col-span-6">
          <div className="flex flex-col gap-6">
            {totalDeal ? <DealsChart /> : null}
            <DashboardActivityLog />
          </div>
        </div>

        <div className="md:col-span-3">
          <Tabs
            value={rightTab}
            onValueChange={setRightTab}
            className="flex flex-col h-[calc(100vh-8rem)]"
          >
            <TabsList className="grid w-full grid-cols-2 mb-3 flex-shrink-0">
              <TabsTrigger value="tasks" className="text-xs">
                <ClipboardList className="h-3.5 w-3.5 mr-1" />
                Tasks
              </TabsTrigger>
              <TabsTrigger value="copilot" className="text-xs">
                <Bot className="h-3.5 w-3.5 mr-1" />
                Copilot
              </TabsTrigger>
            </TabsList>

            <TabsContent value="tasks" className="mt-0">
              <TasksList />
            </TabsContent>

            <TabsContent
              value="copilot"
              className="mt-0 min-h-0 flex flex-col"
              forceMount
            >
              <CopilotWorkspace className="flex-1 min-h-0">
                <div className="flex gap-1.5 flex-wrap px-3 py-2 shrink-0">
                  <Button
                    variant="outline"
                    size="sm"
                    className="text-xs h-7"
                    disabled={agent.isRunning}
                    onClick={() =>
                      triggerAgent(
                        `Triage the top leads. Show the lead priority list.`,
                      )
                    }
                  >
                    <Users className="h-3 w-3 mr-1" />
                    Lead Triage
                  </Button>
                </div>
              </CopilotWorkspace>
            </TabsContent>
          </Tabs>
        </div>
      </div>
    </div>
  );
};

import { useState, useEffect } from "react";

const API_BASE =
  import.meta.env.VITE_COPILOTKIT_API_URL || "http://localhost:4000";

export interface EnrichedContactData {
  lifecycle_stage: string;
  lead_score: number;
  last_activity_date: string;
  last_activity_type: string;
  renewal_amount: number | null;
  renewal_date: string | null;
  renewal_forecast_category: string | null;
  renewal_probability: number | null;
  contract_file: string | null;
  economic_buyer_identified: boolean;
  budget_confirmed: boolean;
  legal_review_status: string;
  security_review_status: string;
  champion_confidence: string;
  competitor: string | null;
  next_best_action: string | null;
  notes_summary: string | null;
}

export function useContactEnrichment(
  firstName?: string,
  lastName?: string,
): { data: EnrichedContactData | null; isLoading: boolean } {
  const [data, setData] = useState<EnrichedContactData | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (!firstName || !lastName) return;
    setIsLoading(true);
    fetch(
      `${API_BASE}/api/contacts?first_name=${encodeURIComponent(firstName)}&last_name=${encodeURIComponent(lastName)}`,
    )
      .then((r) => r.json())
      .then((contacts) => {
        if (Array.isArray(contacts) && contacts.length > 0) {
          setData(contacts[0]);
        }
      })
      .catch((err) => console.warn("Contact enrichment failed:", err))
      .finally(() => setIsLoading(false));
  }, [firstName, lastName]);

  return { data, isLoading };
}

